final_files.sections/testimonial-cards.liquid:
{% comment %}
  Renders testimonial cards section with grid layout
{% endcomment %}

<div class="section-background color-{{ section.settings.color_scheme }}"></div>
<div
  class="section section--{{ section.settings.section_width }} color-{{ section.settings.color_scheme }}"
  data-testid="testimonial-cards-{{ section.id }}"
  style="
    --padding-block-start: {{ section.settings.padding-block-start }}px;
    --padding-block-end: {{ section.settings.padding-block-end }}px;
    --gap: {{ section.settings.gap }}px;
    --columns: {{ section.settings.columns }};
    --mobile-columns: {{ section.settings.mobile_columns }};
  "
>
  <div class="testimonial-cards">
    {% if section.blocks.size > 0 %}
      <div class="testimonial-cards__grid">
        {% for block in section.blocks %}
          {% case block.type %}
            {% when 'testimonial' %}
              <div class="testimonial-card" {{ block.shopify_attributes }}>
                <div class="testimonial-card__content">
                  {% if block.settings.quote != blank %}
                    <blockquote class="testimonial-card__quote">
                      {{ block.settings.quote | escape }}
                    </blockquote>
                  {% endif %}

                  {% if block.settings.rating > 0 %}
                    <div class="testimonial-card__rating">
                      {% for i in (1..5) %}
                        <span class="star {% if i <= block.settings.rating %}star--filled{% endif %}">
                          {% render 'icon', name: 'star' %}
                        </span>
                      {% endfor %}
                    </div>
                  {% endif %}

                  {% if block.settings.customer_name != blank %}
                    <cite class="testimonial-card__customer">
                      {{ block.settings.customer_name | escape }}
                    </cite>
                  {% endif %}
                </div>
              </div>
          {% endcase %}
        {% endfor %}
      </div>
    {% endif %}
  </div>
</div>

<style>
  .testimonial-cards {
    padding-block: var(--padding-block-start) var(--padding-block-end);
  }

  .testimonial-cards__grid {
    display: grid;
    grid-template-columns: repeat(var(--mobile-columns), 1fr);
    gap: var(--gap);
  }

  @media screen and (min-width: 750px) {
    .testimonial-cards__grid {
      grid-template-columns: repeat(var(--columns), 1fr);
    }
  }

  .testimonial-card {
    background: rgba(var(--color-background-contrast), 0.04);
    border-radius: 8px;
    padding: 24px;
    display: flex;
    flex-direction: column;
    text-align: center;
  }

  .testimonial-card__quote {
    font-style: italic;
    margin: 0 0 16px;
    font-size: 1.1em;
    line-height: 1.5;
    color: rgba(var(--color-foreground), 0.8);
  }

  .testimonial-card__quote::before {
    content: '"';
  }

  .testimonial-card__quote::after {
    content: '"';
  }

  .testimonial-card__rating {
    display: flex;
    justify-content: center;
    gap: 4px;
    margin-bottom: 12px;
  }

  .star {
    width: 16px;
    height: 16px;
    color: rgba(var(--color-foreground), 0.3);
  }

  .star--filled {
    color: #ffc107;
  }

  .testimonial-card__customer {
    font-weight: 600;
    color: rgba(var(--color-foreground), 0.9);
    font-style: normal;
    font-size: 0.9em;
  }
</style>

