final_files.sections/countdown-banner.liquid:
{% liquid
  assign end_date = section.settings.end_date
  assign heading = section.settings.heading
  assign background_color = section.settings.background_color
  assign text_color = section.settings.text_color
%}

<div class="countdown-banner" style="background-color: {{ background_color }}; color: {{ text_color }}; padding: 40px 20px; text-align: center;">
  <div class="page-width">
    {% if heading != blank %}
      <h2 class="countdown-banner__heading" style="color: {{ text_color }}; margin-bottom: 20px; font-size: 1.5rem;">{{ heading }}</h2>
    {% endif %}

    {% if end_date != blank %}
      <div class="countdown-timer" id="countdown-{{ section.id }}" data-end-date="{{ end_date }}" style="font-size: 2rem; font-weight: bold; color: {{ text_color }};">
        <div class="countdown-timer__display" style="display: flex; justify-content: center; gap: 20px; flex-wrap: wrap;">
          <div class="countdown-unit">
            <span class="countdown-number" id="days-{{ section.id }}">00</span>
            <div class="countdown-label" style="font-size: 0.8rem; margin-top: 5px; opacity: 0.8;">Days</div>
          </div>
          <div class="countdown-unit">
            <span class="countdown-number" id="hours-{{ section.id }}">00</span>
            <div class="countdown-label" style="font-size: 0.8rem; margin-top: 5px; opacity: 0.8;">Hours</div>
          </div>
          <div class="countdown-unit">
            <span class="countdown-number" id="minutes-{{ section.id }}">00</span>
            <div class="countdown-label" style="font-size: 0.8rem; margin-top: 5px; opacity: 0.8;">Minutes</div>
          </div>
          <div class="countdown-unit">
            <span class="countdown-number" id="seconds-{{ section.id }}">00</span>
            <div class="countdown-label" style="font-size: 0.8rem; margin-top: 5px; opacity: 0.8;">Seconds</div>
          </div>
        </div>
      </div>
    {% endif %}
  </div>
</div>

<script>
(function() {
  const countdownElement = document.getElementById('countdown-{{ section.id }}');
  if (!countdownElement) return;

  const endDate = countdownElement.dataset.endDate;
  if (!endDate) return;

  const targetDate = new Date(endDate + 'T23:59:59').getTime();

  function updateCountdown() {
    const now = new Date().getTime();
    const timeLeft = targetDate - now;

    if (timeLeft < 0) {
      document.getElementById('days-{{ section.id }}').innerText = '00';
      document.getElementById('hours-{{ section.id }}').innerText = '00';
      document.getElementById('minutes-{{ section.id }}').innerText = '00';
      document.getElementById('seconds-{{ section.id }}').innerText = '00';
      return;
    }

    const days = Math.floor(timeLeft / (1000 * 60 * 60 * 24));
    const hours = Math.floor((timeLeft % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    const minutes = Math.floor((timeLeft % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((timeLeft % (1000 * 60)) / 1000);

    document.getElementById('days-{{ section.id }}').innerText = String(days).padStart(2, '0');
    document.getElementById('hours-{{ section.id }}').innerText = String(hours).padStart(2, '0');
    document.getElementById('minutes-{{ section.id }}').innerText = String(minutes).padStart(2, '0');
    document.getElementById('seconds-{{ section.id }}').innerText = String(seconds).padStart(2, '0');
  }

  updateCountdown();
  setInterval(updateCountdown, 1000);
})();
</script>

