final_files.sections/newsletter-popup.liquid:
{% assign delay_ms = section.settings.delay_seconds | times: 1000 %}

<dialog-component>
  <dialog 
    id="newsletter-popup-{{ section.id }}" 
    class="newsletter-popup__dialog"
    data-delay="{{ delay_ms }}"
  >
    <div class="newsletter-popup__overlay">
      <div class="newsletter-popup__content color-{{ section.settings.color_scheme }}">
        <button 
          type="button" 
          class="newsletter-popup__close"
          aria-label="{{ 'actions.close' | t }}"
          onclick="this.closest('dialog-component').closeDialog()"
        >
          <svg viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg" focusable="false" aria-hidden="true" class="newsletter-popup__close-icon">
            {% render 'icon', icon: 'close' %}
          </svg>
        </button>

        <div class="newsletter-popup__header">
          {% if section.settings.heading != blank %}
            <h2 class="newsletter-popup__heading h3">{{ section.settings.heading | escape }}</h2>
          {% endif %}
          {% if section.settings.description != blank %}
            <div class="newsletter-popup__description">
              <p>{{ section.settings.description | escape }}</p>
            </div>
          {% endif %}
        </div>

        <div class="newsletter-popup__form-wrapper">
          {% assign form_id = section.id | prepend: 'NewsletterPopup-' %}
          {%- form 'customer', class: 'newsletter-popup__form' %}
            <input name="contact[id]" type="hidden" value="{{ form_id }}">

            <div class="newsletter-popup__input-group">
              <label for="NewsletterPopupInput-{{ section.id }}" class="visually-hidden">
                {{ 'blocks.email_signup.label' | t }}
              </label>
              <input
                id="NewsletterPopupInput-{{ section.id }}"
                class="newsletter-popup__input"
                type="email"
                name="contact[email]"
                autocorrect="off"
                autocapitalize="off"
                autocomplete="email"
                placeholder="{{ 'blocks.email_signup.placeholder' | t }}"
                required
                {% if form.errors and form.id == form_id %}
                  autofocus
                  aria-invalid="true"
                  aria-describedby="NewsletterPopup-error-{{ section.id }}"
                {% elsif form.posted_successfully? and form.id == form_id %}
                  aria-describedby="NewsletterPopup-success-{{ section.id }}"
                {% endif %}
              >
              <button type="submit" class="newsletter-popup__button button-primary">
                {{ section.settings.button_label | default: 'Subscribe' | escape }}
              </button>
            </div>

            {%- if form.errors and form.id == form_id -%}
              <div id="NewsletterPopup-error-{{ section.id }}" class="newsletter-popup__message newsletter-popup__message--error">
                <svg viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg" focusable="false" aria-hidden="true" class="newsletter-popup__message-icon">
                  {%- render 'icon', icon: 'error'  -%}
                </svg>
                {{- form.errors.translated_fields.email | capitalize }}
                {{ form.errors.messages.email -}}
              </div>
            {%- endif -%}

            {%- if form.posted_successfully? and form.id == form_id -%}
              <div id="NewsletterPopup-success-{{ section.id }}" class="newsletter-popup__message newsletter-popup__message--success">
                <svg viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg" focusable="false" aria-hidden="true" class="newsletter-popup__message-icon">
                  {%- render 'icon', icon: 'checkmark'  -%}
                </svg>
                <p>{{ 'blocks.email_signup.success' | t }}</p>
              </div>
            {%- endif -%}
          {% endform %}
        </div>
      </div>
    </div>
  </dialog>
</dialog-component>

<script>
  document.addEventListener('DOMContentLoaded', function() {
    const popup = document.querySelector('#newsletter-popup-{{ section.id }}');
    const dialogComponent = popup?.closest('dialog-component');
    const delay = parseInt(popup?.dataset.delay) || 5000;

    // Check if popup was already shown in this session
    const popupShown = sessionStorage.getItem('newsletter-popup-shown-{{ section.id }}');

    if (!popupShown && dialogComponent) {
      setTimeout(() => {
        dialogComponent.showDialog();
        sessionStorage.setItem('newsletter-popup-shown-{{ section.id }}', 'true');
      }, delay);
    }

    // Close popup on successful form submission
    const form = popup?.querySelector('form');
    if (form) {
      form.addEventListener('submit', function() {
        setTimeout(() => {
          if (dialogComponent) {
            dialogComponent.closeDialog();
          }
        }, 2000); // Close after 2 seconds to show success message
      });
    }
  });
</script>

