    border: 1px solid rgba(220, 38, 38, 0.2);
  }

  .newsletter-popup__message--success {
    background-color: rgba(34, 197, 94, 0.1);
    color: rgb(34, 197, 94);
    border: 1px solid rgba(34, 197, 94, 0.2);
  }

  .newsletter-popup__message-icon {
    width: 1.25rem;
    height: 1.25rem;
    flex-shrink: 0;
  }

  .newsletter-popup__message p {
    margin: 0;
  }

  /* Animation */
  .newsletter-popup__dialog {
    animation: newsletter-popup-show 0.3s ease-out;
  }

  .newsletter-popup__dialog.dialog-closing {
    animation: newsletter-popup-hide 0.3s ease-out;
  }

  .newsletter-popup__content {
    animation: newsletter-popup-content-show 0.3s ease-out;
  }

  .dialog-closing .newsletter-popup__content {
    animation: newsletter-popup-content-hide 0.3s ease-out;
  }

  @keyframes newsletter-popup-show {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }

  @keyframes newsletter-popup-hide {
    from {
      opacity: 1;
    }
    to {
      opacity: 0;
    }
  }

  @keyframes newsletter-popup-content-show {
    from {
      opacity: 0;
      transform: scale(0.9) translateY(20px);
    }
    to {
      opacity: 1;
      transform: scale(1) translateY(0);
    }
  }

  @keyframes newsletter-popup-content-hide {
    from {
      opacity: 1;
      transform: scale(1) translateY(0);
    }
    to {
      opacity: 0;
      transform: scale(0.9) translateY(20px);
    }
  }

  @media screen and (max-width: 749px) {
    .newsletter-popup__overlay {
      padding: 1rem;
    }

    .newsletter-popup__content {
      padding: 2rem;
      max-width: 100%;
    }

    .newsletter-popup__input-group {
      gap: 1rem;
    }
  }

  @media screen and (min-width: 750px) {
    .newsletter-popup__input-group {
      flex-direction: row;
    }

    .newsletter-popup__input {
      flex: 1;
    }

    .newsletter-popup__button {
      flex-shrink: 0;
    }
  }
{% endstylesheet %}

