final_files.sections/brand-values.liquid:
{% if section.blocks.size > 0 %}
  <div class="section-background color-{{ section.settings.color_scheme }}"></div>
  <div 
    class="section section--{{ section.settings.section_width }} color-{{ section.settings.color_scheme }}"
    data-testid="brand-values-{{ section.id }}"
  >
    <div 
      class="brand-values"
      style="
        --gap: {{ section.settings.gap }}px;
        --columns: {{ section.settings.columns }};
        padding-block-start: {{ section.settings['padding-block-start'] }}px;
        padding-block-end: {{ section.settings['padding-block-end'] }}px;
      "
    >
      {% if section.settings.heading != blank %}
        <div class="brand-values__heading">
          <h2>{{ section.settings.heading }}</h2>
        </div>
      {% endif %}

      <div class="brand-values__grid">
        {% for block in section.blocks %}
          <div 
            class="brand-values__card"
            {{ block.shopify_attributes }}
          >
            {% if block.settings.icon != blank %}
              <div class="brand-values__icon">
                {{ block.settings.icon | image_url: width: 100 | image_tag: alt: block.settings.title, width: 100, height: 100 }}
              </div>
            {% endif %}

            {% if block.settings.title != blank %}
              <h3 class="brand-values__title">{{ block.settings.title }}</h3>
            {% endif %}

            {% if block.settings.description != blank %}
              <div class="brand-values__description">
                {{ block.settings.description | newline_to_br }}
              </div>
            {% endif %}
          </div>
        {% endfor %}
      </div>
    </div>
  </div>

  <style>
    .brand-values {
      container-type: inline-size;
    }

    .brand-values__heading {
      text-align: center;
      margin-bottom: calc(var(--gap) * 2);
    }

    .brand-values__grid {
      display: grid;
      grid-template-columns: repeat(var(--columns), 1fr);
      gap: var(--gap);
    }

    .brand-values__card {
      text-align: center;
      padding: 2rem;
      border-radius: 8px;
      background: rgba(var(--color-foreground), 0.02);
    }

    .brand-values__icon {
      margin-bottom: 1rem;
    }

    .brand-values__icon img {
      width: 60px;
      height: 60px;
      object-fit: contain;
    }

    .brand-values__title {
      margin-bottom: 0.5rem;
      font-size: 1.25rem;
      font-weight: 600;
    }

    .brand-values__description {
      color: rgba(var(--color-foreground), 0.75);
      line-height: 1.5;
    }

    @container (max-width: 768px) {
      .brand-values__grid {
        grid-template-columns: 1fr;
      }
    }

    @container (min-width: 769px) and (max-width: 1024px) {
      .brand-values__grid {
        grid-template-columns: repeat(2, 1fr);
      }
    }
  </style>
{% endif %}

